  ('heelevel3-8b44517b-moex-00287', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-110-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '訴願人提起訴願，請求為特定內容之行政處分，在訴願決定作成前，應作為之機關已作成不利於 訴願人之行政處分。受理訴願機關應為如何之處置？', '["應以訴願為不合法，為不受理之決定", "應逕認訴願為無理由，以決定駁回之", "應逕認訴願為有理由者，將原處分撤銷", "應續行訴願程序，對嗣後所為之行政處分併為實體審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "311", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00288', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-110-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '有關訴願管轄之敘述，下列何者錯誤？', '["對縣政府辦理委辦事件所為之行政處分不服者，向縣政府之直接上級機關提起訴願", "對無隸屬關係之機關辦理受委託事件所為之行政處分不服者，向原委託機關或其直接上級機關 提起訴願", "對有隸屬關係之機關辦理受委任事件所為之行政處分不服者，向原委任機關之直接上級機關提 起訴願", "對受託行使公權力之個人所為之行政處分不服者，向原委託機關提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "311", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('heelevel3-8b44517b-moex-00289', 'heelevel3-8b44517b', 'heelevel3-8b44517b-moex-110-3082b5f1', 'sub-heelevel3-8b44517b-04', NULL, 'single_choice', '關於行政訴訟訴訟費用之敘述，下列何者錯誤？', '["適用簡易訴訟程序之事件，徵收裁判費新臺幣2,000元", "適用通常訴訟程序之事件，按件徵收裁判費新臺幣4,000元", "訴訟費用原則上由敗訴之當事人負擔", "依行政訴訟法第198條為情況判決時，其訴訟費用由敗訴之原告負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:12+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "311", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "勞工行政"}'::jsonb, NULL),
